const account = $input.item.json;

let expansionScore = 0;
const signals = [];
const plays = [];

// Usage exceeding plan limits
const usagePercent = (account.current_usage / account.plan_limit) * 100;
if (usagePercent > 90) {
  expansionScore += 30;
  signals.push(`Usage at ${Math.round(usagePercent)}% of plan limit`);
  plays.push('Propose plan upgrade before overage charges');
}
if (usagePercent > 110) {
  expansionScore += 10;
  signals.push('Already exceeding plan limits');
}

// New department adoption
if (account.new_departments > 0) {
  expansionScore += 25;
  signals.push(`${account.new_departments} new department(s) started using the product`);
  plays.push('Offer enterprise-wide licensing deal');
}

// Feature requests for higher-tier features
const premiumRequests = (account.feature_requests || []).filter(r => r.tier === 'premium' || r.tier === 'enterprise');
if (premiumRequests.length > 0) {
  expansionScore += 20;
  signals.push(`${premiumRequests.length} requests for higher-tier features`);
  plays.push(`Demo premium features: ${premiumRequests.map(r => r.name).join(', ')}`);
}

// Positive usage trend
if (account.usage_growth_percent > 20) {
  expansionScore += 15;
  signals.push(`Usage growing ${account.usage_growth_percent}% month-over-month`);
}

// High NPS/satisfaction
if (account.latest_nps >= 9) {
  expansionScore += 10;
  signals.push(`NPS score: ${account.latest_nps} (promoter)`);
  plays.push('Request case study or referral alongside expansion conversation');
}

if (expansionScore < 20) return [];

return [{
  json: {
    account_id: account.account_id,
    account_name: account.account_name,
    current_arr: account.arr,
    current_plan: account.plan_name,
    expansion_score: expansionScore,
    signals: signals,
    suggested_plays: plays,
    estimated_expansion: Math.round(account.arr * 0.3),
    csm_email: account.csm_email,
    ae_email: account.ae_email
  }
}];

